const patterns = [
  { regex: /\b\d{3}-?\d{2}-?\d{4}\b/g, token: "[SSN-REDACTED]" },
  { regex: /\b\d{2}-\d{7}\b/g, token: "[EIN-REDACTED]" },
  { regex: /\b\d{8,17}\b/g, token: "[ACCOUNT-REDACTED]" },
  { regex: /\b\d{9}\b/g, token: "[ROUTING-REDACTED]" },
  { regex: /\b(?:\d[ -]*?){13,16}\b/g, token: "[CARD-REDACTED]" },
];

return $input.all().map(item => {
  let safeSubject = item.json.subject || '';
  let safeBody = item.json.text || item.json.html || '';

  for (const p of patterns) {
    safeSubject = safeSubject.replace(p.regex, p.token);
    safeBody = safeBody.replace(p.regex, p.token);
  }

  const fromAddr = item.json.from?.value?.[0]?.address || item.json.from || '';
  const domain = (fromAddr.split('@')[1] || '').toLowerCase();

  return {
    json: {
      ...item.json,
      sender_domain: domain,
      subject_original: item.json.subject,
      body_original: item.json.text,
      subject: safeSubject,
      body: safeBody,
    }
  };
});

